import{j as e}from"./ui-vendor-CUvJdy9K.js";import{S as r}from"./ServicePageTemplate-b_yPsRG4.js";import{W as a}from"./wrench-B_q1B9p_.js";import"./react-vendor-CSY-tL5Y.js";import"./index-DwoQH_UC.js";import"./Footer-cFgvTlX-.js";import"./phone-NIeGsEvO.js";import"./AnimatedSection-CgPtTXO5.js";import"./breadcrumb-dwwOUC4l.js";import"./index-wnGSTn9f.js";import"./utils-BLSKlp9E.js";import"./sections-t0Spbv1x.js";import"./accordion-C4vxtsvR.js";import"./circle-check-big-C2xgjNoD.js";const f=()=>e.jsx(r,{title:"Underhåll & Support",metaTitle:"Webbunderhåll & support Västmanland | LRH Konsult",metaDescription:"Personlig webbsupport och underhåll i Västmanland. Dagliga backuper, säkerhetsuppdateringar och dygnet-runt-övervakning för företag i Västerås.",heroSubheading:"Underhåll & Support",heroHeading:"Underhåll & Support – trygg webbdrift",heroDescription:"Lämna det tekniska till oss. Vi erbjuder marknadens tryggaste underhåll och support för företag i hela Västmanlands län. Vi ser till att din hemsida alltid är uppdaterad, snabb och skyddad mot digitala hot.",whyTitle:"Din lokala webbpartner i Västmanland",whyText:"Med personlig support från Västmanland får du hjälp direkt när du behöver det. Vi övervakar din sajt dygnet runt och agerar proaktivt för att förhindra problem innan de uppstår – så att du kan fokusera fullt ut på att driva din verksamhet.",icon:a,breadcrumbLabel:"Underhåll & Support",features:[{title:"Dagliga backuper",description:"Automatiska dagliga backuper med snabb återställning inom 15 minuter om något skulle gå fel."},{title:"Säkerhetsuppdateringar",description:"Regelbundna uppdateringar av CMS, plugins och server för att stänga säkerhetshål och hålla systemet aktuellt."},{title:"Övervakning dygnet runt",description:"Uptime-monitoring som larmar direkt om din sajt går ner – med snabb åtgärd och minimal nertid."},{title:"Teknisk support",description:"Snabb hjälp med innehållsuppdateringar, buggfixar, nya funktioner och tekniska frågor."},{title:"Månadsrapport",description:"Tydlig rapport varje månad med status, genomförda uppdateringar, prestanda-data och rekommendationer."}],faqTitle:"Vanliga frågor om webbunderhåll",faq:[{question:"Vad händer om min hemsida går ner?",answer:"Vi övervakar sajten dygnet runt och återställer den direkt från våra dagliga backuper om något sker. Du får ett larm och statusuppdatering inom minuter."},{question:"Hjälper ni till med e-post och domäner också?",answer:"Ja, vi kan hantera hela din digitala infrastruktur – domäner, e-post, hosting och DNS – för en krångelfri vardag."},{question:"Hur kontaktar jag supporten?",answer:"Du når oss via mejl eller telefon. Vi finns lokalt i Västmanland för snabb hantering och personlig kontakt."},{question:"Kan ni ta över en sajt byggd av annan byrå?",answer:"Ja, vi tar regelbundet över webbplatser från andra leverantörer. Vi gör alltid en teknisk genomgång först för att säkerställa full kontroll."}],contentSections:[{title:"Vad trygg drift och support innebär",paragraphs:["En webbplats som ligger nere kostar pengar och förtroende – särskilt om den hanterar bokningar, felanmälningar eller kontaktformulär. Ett enda driftstopp under en helg kan innebära missade affärer och frustrerade kunder. Därför handlar bra drift om att förebygga problem innan de uppstår.","Vi erbjuder ett komplett övervaknings- och backupsystem: sajten övervakas dygnet runt med automatiska larm vid driftstörningar, dagliga backuper med snabb återställning, samt löpande säkerhetsuppdateringar av alla komponenter.","Med proaktiv övervakning upptäcks och åtgärdas potentiella problem ofta innan de hinner påverka dina besökare. Du kan fokusera på din verksamhet med vetskapen att din digitala närvaro är i trygga händer."]},{title:"Vad ingår i professionellt webbunderhåll?",paragraphs:["Professionellt webbunderhåll handlar om mer än att bara hålla sajten igång. Det handlar om att proaktivt skydda din investering och säkerställa att din webbplats fortsätter att prestera optimalt. En sajt som inte underhålls regelbundet blir gradvis långsammare, mer sårbar för attacker och tappar ranking i sökmotorerna.","Våra månadsavtal inkluderar dagliga backuper, säkerhetsuppdateringar, uptime-övervakning med automatiska larm, teknisk support via mejl och telefon, samt en månadsrapport med status och rekommendationer. Vi anpassar alltid paketet efter din verksamhets specifika behov och budget.","Kan ni ta över driften av en sajt som någon annan har byggt? Ja, vi tar regelbundet över webbplatser som byggts av andra byråer eller frilansare. Vi börjar alltid med en teknisk genomgång för att identifiera eventuella problem, säkerhetsluckor och prestandaflaskhalsar innan vi lägger in sajten i vårt övervaknings- och underhållssystem."]},{title:"Vad det kostar att inte underhålla sin sajt",paragraphs:["Många företag ser underhåll som en valfri kostnad – ända tills något går fel. En sajt utan löpande uppdateringar blir med tiden en måltavla: kända säkerhetshål i föråldrade plugins och teman utnyttjas av automatiserade attacker, och en hackad sajt kan innebära allt från spam-injektioner till att Google flaggar din webbplats som osäker.","Utöver säkerheten tappar en oövervakad sajt gradvis prestanda och ranking. Plugins slutar fungera tillsammans, laddtiderna kryper uppåt och trasiga sidor upptäcks ofta först när en kund hör av sig – eller värre, när de redan vänt sig till en konkurrent. Ett enda obemärkt driftstopp kan kosta mer än ett helt års underhåll.","Med ett underhållsavtal hos oss byter du oförutsägbara akutkostnader mot en förutsägbar månadsavgift och vetskapen att någon håller koll. Du får en kontaktperson som känner din sajt, snabb hjälp när du behöver ändra något, och en plattform som förblir snabb, säker och synlig på Google år efter år."]}],relatedServices:[{label:"Prestanda-optimering",href:"/tjanster/prestanda-optimering"},{label:"WordPress-lösningar",href:"/tjanster/wordpress-losningar"},{label:"Webbutveckling",href:"/tjanster/webbutveckling"}]});export{f as default};
